# oncall/hypercare_rotation.py
# Manage the hypercare on-call rotation for the first 30 days.
from dataclasses import dataclass, field
from datetime import date, timedelta
from typing import List

@dataclass
class Shift:
    engineer: str
    start: date
    end: date          # inclusive
    primary: bool = True
    pagerduty_id: str = ''

@dataclass
class HypercareRotation:
    launch_date: date
    shifts: List[Shift] = field(default_factory=list)

    def week(self, d: date) -> int:
        return (d - self.launch_date).days // 7 + 1

    def shift_duration(self, week: int) -> int:
        # Week 1: 24h shifts (max coverage)
        # Week 2: 48h shifts
        # Weeks 3-4: 72h shifts (normal 3-day on-call)
        return {1: 1, 2: 2}.get(week, 3)

    def current_primary(self, d: date = None) -> Shift | None:
        d = d or date.today()
        for shift in self.shifts:
            if shift.primary and shift.start <= d <= shift.end:
                return shift
        return None

    def coverage_gaps(self) -> List[date]:
        covered = set()
        for shift in self.shifts:
            d = shift.start
            while d <= shift.end:
                covered.add(d)
                d += timedelta(days=1)
        end = self.launch_date + timedelta(days=30)
        gaps = []
        d = self.launch_date
        while d <= end:
            if d not in covered:
                gaps.append(d)
            d += timedelta(days=1)
        return gaps

# Example usage
rotation = HypercareRotation(launch_date=date(2026, 7, 1))
rotation.shifts = [
    Shift('alice', date(2026, 7, 1), date(2026, 7, 1)),
    Shift('bob',   date(2026, 7, 2), date(2026, 7, 2)),
    Shift('alice', date(2026, 7, 3), date(2026, 7, 4)),
    # ... fill remaining 30 days
]
gaps = rotation.coverage_gaps()
if gaps:
    print(f'WARNING: {len(gaps)} uncovered days: {gaps[:3]}...')
